def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
        else:
            diff = capacity - item
            score = 0
            for j in range(1, int(diff) + 1):
                if j % 2 == 0:
                    score += j / (diff + 1)
                else:
                    score -= j / (diff + 1)
            if diff == 0:
                priorities[i] = 0
            else:
                priorities[i] = (score + 1) / diff
    min_priority = np.min(priorities[np.isfinite(priorities)])
    for k in range(len(priorities)):
        if not np.isfinite(priorities[k]):
            priorities[k] = 2 * min_priority
    return priorities
